 10	// TestInjectMetaPrompt tests meta-prompt injection
 11	func TestInjectMetaPrompt(t *testing.T) {
 12		tests := []struct {
 13			name          string
 14			existingFile  string
 15			promptPath    string
 16			promptContent string
 17			expectError   bool
 18			expectContent string
 19		}{
 20			{
 21				name:          "inject into new file",
 22				existingFile:  "",
 23				promptPath:    "claude/system-prompts/test.md",
 24				promptContent: "# Test Prompt\nContent here",
 25				expectError:   false,
 26				expectContent: "<!-- DDX-META-PROMPT:START -->",
 27			},
 28			{
 29				name:          "inject into existing file",
 30				existingFile:  "# CLAUDE.md\n\nExisting content",
 31				promptPath:    "claude/system-prompts/test.md",
 32				promptContent: "# Test Prompt",
 33				expectError:   false,
 34				expectContent: "Existing content",
 35			},
 36			{
 37				name:          "replace existing meta-prompt",
 38				existingFile:  "Content\n<!-- DDX-META-PROMPT:START -->\nOld\n<!-- DDX-META-PROMPT:END -->",
 39				promptPath:    "claude/system-prompts/new.md",
 40				promptContent: "New prompt",
 41				expectError:   false,
 42				expectContent: "New prompt",
 43			},
 44			{
 45				name:         "prompt file not found",
 46				existingFile: "",
 47				promptPath:   "nonexistent/prompt.md",
 48				expectError:  true,
 49			},
 50			{
 51				name:          "prompt too large",
 52				existingFile:  "",
 53				promptPath:    "claude/system-prompts/huge.md",
 54				promptContent: strings.Repeat("x", MaxMetaPromptSize+1),
 55				expectError:   true,
 56			},
 57			{
 58				name:         "empty prompt path",
 59				existingFile: "",
 60				promptPath:   "",
 61				expectError:  true,
 62			},
 63			{
 64				name:          "preserves content outside markers",
 65				existingFile:  "Before\n<!-- DDX-META-PROMPT:START -->\nOld\n<!-- DDX-META-PROMPT:END -->\nAfter",
 66				promptPath:    "claude/system-prompts/test.md",
 67				promptContent: "New",
 68				expectError:   false,
 69				expectContent: "Before",
 70			},
 71		}
 72	
 73		for _, tt := range tests {
 74			t.Run(tt.name, func(t *testing.T) {
 75				// Setup test directory
 76				testDir := t.TempDir()
 77				claudePath := filepath.Join(testDir, "CLAUDE.md")
 78				libraryPath := filepath.Join(testDir, ".ddx", "plugins", "ddx")
 79	
 80				// Create library directory structure
 81				promptDir := filepath.Join(libraryPath, "prompts", filepath.Dir(tt.promptPath))
 82				if err := os.MkdirAll(promptDir, 0755); err != nil {
 83					t.Fatalf("Failed to create prompt dir: %v", err)
 84				}
 85	
 86				// Create prompt file if content provided
 87				if tt.promptContent != "" {
 88					promptFile := filepath.Join(libraryPath, "prompts", tt.promptPath)
 89					if err := os.WriteFile(promptFile, []byte(tt.promptContent), 0644); err != nil {
 90						t.Fatalf("Failed to create prompt file: %v", err)
 91					}
 92				}
 93	
 94				// Create existing CLAUDE.md if provided
 95				if tt.existingFile != "" {
 96					if err := os.WriteFile(claudePath, []byte(tt.existingFile), 0644); err != nil {
 97						t.Fatalf("Failed to create CLAUDE.md: %v", err)
 98					}
 99				}
100	
101				// Create injector
102				injector := NewMetaPromptInjectorWithPaths(
103					"CLAUDE.md",
104					filepath.Join(".ddx", "plugins", "ddx"),
105					testDir,
106				)
107	
108				// Test injection
109				err := injector.InjectMetaPrompt(tt.promptPath)
110	
111				// Check error expectation
112				if tt.expectError && err == nil {
113					t.Errorf("Expected error but got none")
114				}
115				if !tt.expectError && err != nil {
116					t.Errorf("Unexpected error: %v", err)
117				}
118	
119				// Verify content if no error expected
120				if !tt.expectError && tt.expectContent != "" {
121					content, err := os.ReadFile(claudePath)
122					if err != nil {
123						t.Fatalf("Failed to read CLAUDE.md: %v", err)
124					}
125					if !strings.Contains(string(content), tt.expectContent) {
126						t.Errorf("Expected content to contain %q, got:\n%s", tt.expectContent, string(content))
127					}
128				}
129	
130				// Verify markers are present when successful
131				if !tt.expectError {
132					content, _ := os.ReadFile(claudePath)
133					if !strings.Contains(string(content), MetaPromptStartMarker) {
134						t.Errorf("Missing start marker in CLAUDE.md")
135					}
136					if !strings.Contains(string(content), MetaPromptEndMarker) {
137						t.Errorf("Missing end marker in CLAUDE.md")
138					}
139				}
140			})
141		}
142	}
