144	// TestIsInSync tests sync detection
145	func TestIsInSync(t *testing.T) {
146		t.Run("in sync after injection", func(t *testing.T) {
147			// Setup test directory
148			testDir := t.TempDir()
149			libraryPath := filepath.Join(testDir, ".ddx", "plugins", "ddx")
150			promptPath := "claude/system-prompts/test.md"
151			promptContent := "Test prompt content"
152	
153			// Create library prompt
154			promptDir := filepath.Join(libraryPath, "prompts", "claude", "system-prompts")
155			if err := os.MkdirAll(promptDir, 0755); err != nil {
156				t.Fatalf("Failed to create prompt dir: %v", err)
157			}
158			promptFile := filepath.Join(libraryPath, "prompts", promptPath)
159			if err := os.WriteFile(promptFile, []byte(promptContent), 0644); err != nil {
160				t.Fatalf("Failed to create prompt file: %v", err)
161			}
162	
163			// Create injector and inject
164			injector := NewMetaPromptInjectorWithPaths("CLAUDE.md", filepath.Join(".ddx", "plugins", "ddx"), testDir)
165			if err := injector.InjectMetaPrompt(promptPath); err != nil {
166				t.Fatalf("Failed to inject: %v", err)
167			}
168	
169			// Check sync - should be in sync
170			inSync, err := injector.IsInSync()
171			if err != nil {
172				t.Errorf("Unexpected error: %v", err)
173			}
174			if !inSync {
175				t.Errorf("Expected in sync after injection")
176			}
177		})
178	
