292	// TestRemoveMetaPrompt tests meta-prompt removal
293	func TestRemoveMetaPrompt(t *testing.T) {
294		tests := []struct {
295			name          string
296			input         string
297			expectContent string
298			expectError   bool
299		}{
300			{
301				name:          "remove existing section",
302				input:         "Before\n<!-- DDX-META-PROMPT:START -->\nPrompt\n<!-- DDX-META-PROMPT:END -->\nAfter",
303				expectContent: "Before\n\nAfter",
304				expectError:   false,
305			},
306			{
307				name:          "no section to remove",
308				input:         "# CLAUDE.md\n\nNo meta-prompt here",
309				expectContent: "# CLAUDE.md\n\nNo meta-prompt here",
310				expectError:   false,
311			},
312			{
313				name:          "malformed section (no end marker)",
314				input:         "Content\n<!-- DDX-META-PROMPT:START -->\nNo end marker",
315				expectContent: "Content",
316				expectError:   false,
317			},
318			{
319				name:          "section at start",
320				input:         "<!-- DDX-META-PROMPT:START -->\nPrompt\n<!-- DDX-META-PROMPT:END -->\nAfter",
321				expectContent: "After",
322				expectError:   false,
323			},
324			{
325				name:          "section at end",
326				input:         "Before\n<!-- DDX-META-PROMPT:START -->\nPrompt\n<!-- DDX-META-PROMPT:END -->",
327				expectContent: "Before",
328				expectError:   false,
329			},
330			{
331				name:          "file doesn't exist",
