376						if strings.TrimSpace(string(content)) != strings.TrimSpace(tt.expectContent) {
377							t.Errorf("Expected content:\n%s\n\nGot:\n%s", tt.expectContent, string(content))
378						}
379					} else if tt.expectContent != "" {
380						t.Errorf("Expected file to exist with content, but it doesn't")
381					}
382				}
383			})
