454	// Helper function to build CLAUDE.md with meta-prompt section
455	func buildCLAUDEWithPrompt(promptContent, sourcePath string) string {
456		return strings.Join([]string{
457			"# CLAUDE.md",
458			"",
459			"Project content here",
460			"",
461			MetaPromptStartMarker,
462			"<!-- Source: " + sourcePath + " -->",
463			promptContent,
464			MetaPromptEndMarker,
465			"",
466			"More content",
467		}, "\n")
468	}

